import React, { useEffect, useState } from 'react';

const videoSources = {
  beaches: 'https://cdn.coverr.co/videos/coverr-aerial-view-of-a-drone-flying-over-a-beach-2358/1080p.mp4',
  temples: 'https://cdn.coverr.co/videos/coverr-temple-courtyard-full-of-smoke-2655/1080p.mp4',
  trekking: 'https://cdn.coverr.co/videos/coverr-hiker-walking-along-a-mountain-ridge-2004/1080p.mp4',
  adventure: 'https://cdn.coverr.co/videos/coverr-adventure-paddle-boarder-on-a-lake-1752/1080p.mp4',
  nature: 'https://cdn.coverr.co/videos/coverr-forest-waterfall-1784/1080p.mp4',
  cultural: 'https://cdn.coverr.co/videos/coverr-city-scene-with-building-lights-2982/1080p.mp4',
  scenic: 'https://cdn.coverr.co/videos/coverr-sunrise-over-mountain-lake-1938/1080p.mp4'
};

const getVideoSrc = (type) => videoSources[type] || videoSources.scenic;

function BackgroundVideo({ videoType }) {
  const [currentSrc, setCurrentSrc] = useState(getVideoSrc(videoType));
  const [fadeKey, setFadeKey] = useState(0);

  useEffect(() => {
    const newSrc = getVideoSrc(videoType);
    if (newSrc !== currentSrc) {
      setFadeKey((key) => key + 1);
      setCurrentSrc(newSrc);
    }
  }, [videoType, currentSrc]);

  return (
    <div className="app-video-wrap">
      <video
        key={`${currentSrc}-${fadeKey}`}
        className="app-video-background"
        autoPlay
        muted
        loop
        playsInline
        preload="metadata"
      >
        <source src={currentSrc} type="video/mp4" />
      </video>
      <div className="video-overlay" />
    </div>
  );
}

export default BackgroundVideo;
